"<?php

namespace App\Exports;

use App\Models\AnggotaRombel;
use App\Models\MataPelajaran;
use App\Models\NilaiSkl;
use Maatwebsite\Excel\Concerns\FromCollection;
use Maatwebsite\Excel\Concerns\WithHeadings;

class TemplateNilaiSklExport implements FromCollection, WithHeadings
{
    protected $kelas_id;
    protected $semester_id;

    public function __construct($kelas_id, $semester_id)
    {
        $this->kelas_id = $kelas_id;
        $this->semester_id = $semester_id;
    }

    public function collection()
    {
        $mapels = MataPelajaran::orderBy('nama')->get();
        $anggotaRombel = AnggotaRombel::with(['siswa'])
            ->where('kelas_id', $this->kelas_id)
            ->where('semester_id', $this->semester_id)
            ->get()->sortBy('siswa.nama');

        $data = [];
        foreach ($anggotaRombel as $ar) {
            $row = [
                'ID_SISWA' => $ar->siswa_id,
                'NISN' => $ar->siswa->nisn ?? '-',
                'NAMA_SISWA' => $ar->siswa->nama ?? 'Tanpa Nama',
            ];

            foreach ($mapels as $mapel) {
                $nilai = NilaiSkl::where('siswa_id', $ar->siswa_id)
                                ->where('mata_pelajaran_id', $mapel->id)
                                ->first();
                $row['MAPEL_' . $mapel->id] = $nilai ? $nilai->nilai_ujian : 0;
            }

            $data[] = $row;
        }

        return collect($data);
    }

    public function headings(): array
    {
        $mapels = MataPelajaran::orderBy('nama')->get();
        $headings = ['ID_SISWA', 'NISN', 'NAMA_SISWA'];
        foreach ($mapels as $mapel) {
            $headings[] = $mapel->nama . ' (ID:' . $mapel->id . ')';
        }
        return $headings;
    }
}
