                    'keterangan' => 'LULUS',
                    'pesan' => 'Selamat! Anda dinyatakan LULUS dari sekolah.'
                ]
            ]);
        }

        return response()->json([
            'status' => 'error',
            'message' => 'Data dengan NISN tersebut tidak ditemukan.'
        ], 404);
    }

    public function verifikasiSkl($id, $hash)
    {
        $siswa = Siswa::findOrFail($id);
        $validHash = md5($siswa->nisn . $siswa->id . 'SKL2026');

        if ($hash !== $validHash) {
            abort(404, 'Kode verifikasi SKL tidak valid atau palsu.');
        }

        $kelulusan = Kelulusan::where('siswa_id', $id)->first();
        $sekolah = Sekolah::first();

        return view('public.verifikasi', compact('siswa', 'kelulusan', 'sekolah'));
    }
}"

