        if ($this->kelas_id) {
            $query->where('anggota_rombels.kelas_id', $this->kelas_id);
        }

        $anggotaRombel = $query->get()->sortBy(['kelas.nama', 'siswa.nama']);
        $jumlahMapelSkl = MataPelajaran::where('tampil_skl', 1)->count();

        $data = [];
        $no = 1;

        foreach ($anggotaRombel as $ar) {
            $totalNilai = $ar->siswa->nilaiSkl->filter(function($nilai) {
                return $nilai->mataPelajaran && $nilai->mataPelajaran->tampil_skl == 1;
            })->sum('nilai_ujian');

            $rataRata = $jumlahMapelSkl > 0 ? ($totalNilai / $jumlahMapelSkl) : 0;

            $data[] = [
                'NO' => $no++,
                'NISN' => $ar->siswa->nisn ?? '-',
                'NAMA_SISWA' => $ar->siswa->nama ?? 'Tanpa Nama',
                'KELAS' => $ar->kelas->nama ?? '-',
                'RATA_RATA_SKL' => round($rataRata, 2),
                'STATUS_KELULUSAN' => $ar->siswa->kelulusan ? $ar->siswa->kelulusan->status : 'Belum Diumumkan',
                'NO_SURAT' => $ar->siswa->kelulusan ? $ar->siswa->kelulusan->no_surat : '-'
            ];
        }

        return collect($data);
    }

