"<?php

namespace App\Exports;

use App\Models\Pembelajaran;
use App\Models\AnggotaRombel;
use App\Models\NilaiRaport;
use Maatwebsite\Excel\Concerns\FromCollection;
use Maatwebsite\Excel\Concerns\WithHeadings;
use Maatwebsite\Excel\Concerns\WithMapping;

class NilaiRaportExport implements FromCollection, WithHeadings, WithMapping
{
    protected $pembelajaran;

    public function __construct(Pembelajaran $pembelajaran)
    {
        $this->pembelajaran = $pembelajaran;
    }

    public function collection()
    {
        return AnggotaRombel::with('siswa')
            ->where('kelas_id', $this->pembelajaran->kelas_id)
            ->where('semester_id', session('semester_id'))
            ->get();
    }

    public function headings(): array
    {
        return [
            'ID Anggota Rombel', // This must be kept so we know who to update
            'NISN',
            'Nama Siswa',
            'Nilai Raport',
        ];
    }

    public function map($anggota): array
    {
        $nilai = NilaiRaport::where('pembelajaran_id', $this->pembelajaran->id)
            ->where('anggota_rombel_id', $anggota->id)
            ->first();

        return [
            $anggota->id,
            $anggota->siswa->nisn ?? '-',
            $anggota->siswa->nama ?? 'Unknown',
            $nilai ? $nilai->nilai : '',
        ];
    }
}"

"<?php

namespace App\Imports;

use App\Models\Pembelajaran;
use App\Models\NilaiRaport;
use Maatwebsite\Excel\Concerns\ToModel;
use Maatwebsite\Excel\Concerns\WithHeadingRow;

class NilaiRaportImport implements ToModel, WithHeadingRow
{
    protected $pembelajaran;

    public function __construct(Pembelajaran $pembelajaran)
    {
        $this->pembelajaran = $pembelajaran;
    }

    public function model(array $row)
    {
        if (!isset($row['id_anggota_rombel']) || empty($row['id_anggota_rombel'])) {
            return null;
        }

        // Cari atau buat record nilai baru
        $nilai = NilaiRaport::updateOrCreate(
            [
                'pembelajaran_id' => $this->pembelajaran->id,
                'anggota_rombel_id' => $row['id_anggota_rombel'],
            ],
            [
                'nilai' => isset($row['nilai_raport']) && is_numeric($row['nilai_raport']) ? $row['nilai_raport'] : null,
            ]
        );

        return $nilai;
    }
}"

